-- Seed: Weekly Sales from OA WIP SHEET_UPDATED 16 JAN.xlsx
-- Generated by scripts/seed_weekly_sales_from_workbook.py. Safe to re-run.

delete from public.weekly_sales where month_year in ('APRIL 2025', 'APRIL 2026', 'AUGUST 2025', 'DECEMBER 2025', 'FEBRUARY 2025', 'FEBRUARY 2026', 'JANUARY 2025', 'JANUARY 2026', 'JULY 2025', 'JUNE 2025', 'MARCH 2025', 'MARCH 2026', 'MAY 2025', 'NOVEMBER 2025', 'OCTOBER 2025', 'SEPTEMBER 2025');

on conflict (date) do update set
  event_name = excluded.event_name,
  pax = excluded.pax,
  table_bookings = excluded.table_bookings,
  door_sales = excluded.door_sales,
  cover_charge = excluded.cover_charge,
  pos_total = excluded.pos_total,
  ticketmelon_total = excluded.ticketmelon_total,
  weekly_target = excluded.weekly_target,
  week_number = excluded.week_number,
  month_year = excluded.month_year,
  utilities = excluded.utilities,
  man_power = excluded.man_power,
  local_dj = excluded.local_dj,
  ambassador_commission = excluded.ambassador_commission,
  intl_artist_cost = excluded.intl_artist_cost,
  puspal = excluded.puspal,
  hotel = excluded.hotel,
  rider = excluded.rider,
  bar_split = excluded.bar_split,
  misc = excluded.misc,
  online_ticket = excluded.online_ticket,
  walkin_ticket = excluded.walkin_ticket,
  sponsorship = excluded.sponsorship;
